public class Purchase
{
    public int Id { get; set; }
    public int TicketQuantity { get; set; }
    public DateTimeOffset PurchaseTime { get; set; }
    public int EventId { get; set; }
    public Event Event { get; set; }
}

public class ApplicationDbContext : DbContext
{
    public DbSet<Event> Events { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder options) =>
        options.UseSqlServer(ConnectionString); // Replace ConnectionString with your connection string

    public async Task<int> BuyTicketAsync(int eventId, int ticketQuantity, CancellationToken cancellationToken = default)
    {
        var @event = await Events.FindAsync(eventId, cancellationToken);

        if (@event == null || @event.RemainingSeats < ticketQuantity)
            throw new InvalidOperationException("Event not found or there are not enough remaining seats.");

        var purchaseEntity = new Purchase { TicketQuantity = ticketQuantity, EventId = eventId, PurchaseTime = DateTimeOffset.UtcNow };
        await Database.BeginTransactionAsync(cancellationToken);

        try
        {
            EnterDatabaseLock(purchaseEntity, @event, cancellationToken);
            await SaveChangesAsync(cancellationToken);
            await DecrementRemainingSeatsAsync(@event, ticketQuantity, cancellationToken);
            await Database.CommitTransactionAsync(cancellationToken);

            return purchaseEntity.Id;
        }
        catch
        {
            await Database.RollbackTransactionAsync(cancellationToken);
            throw;
        }
    }

    private void EnterDatabaseLock(Purchase purchase, Event @event, CancellationToken cancellationToken)
    {
        var lockEntity = new LockEntity { PurchaseId = purchase.Id, EventId = @event.Id, LockedAt = DateTimeOffset.UtcNow };
        Database.Entry(lockEntity).State = EntityState.Added;
    }

    private async Task DecrementRemainingSeatsAsync(Event @event, int ticketQuantity, CancellationToken cancellationToken)
    {
        await Task.Run(() => @event.RemainingSeats -= ticketQuantity, cancellationToken);
    }
}

public class LockEntity
{
    public int PurchaseId { get; set; }
    public int EventId { get; set; }
    public DateTimeOffset LockedAt { get; set; }
}